import sys
input = sys.stdin.readline

def solve():
    n, m = map(int, input().split())
    x = list(map(int, input().split()))
    s = [input().strip() for _ in range(n)]

    types = []
    for j in range(m):
        mask = 0
        for i in range(n):
            if s[i][j] == '1':
                mask |= (1 << i)
        types.append(mask)

    from collections import Counter
    cnt = Counter(types)
    type_list = list(cnt.keys())
    remaining = dict(cnt)

    r = [0] * n
    assignment = {}  # type -> list of values
    for t in type_list:
        assignment[t] = []

    # Process values from largest to smallest
    for v in range(m, 0, -1):
        best_gain = -1
        best_t = None
        for t in type_list:
            if remaining[t] == 0:
                continue
            gain = 0
            for i in range(n):
                if t & (1 << i):
                    old = abs(x[i] - r[i])
                    new = abs(x[i] - r[i] - v)
                    gain += new - old
            if best_t is None or gain > best_gain:
                best_gain = gain
                best_t = t
        remaining[best_t] -= 1
        assignment[best_t].append(v)
        for i in range(n):
            if best_t & (1 << i):
                r[i] += v

    result = []
    for j in range(m):
        t = types[j]
        result.append(assignment[t].pop())

    print(*result)

t = int(input())
for _ in range(t):
    solve()

